var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。","ENG":"that you'll be with him, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called him to your office. He said he'd be here soon.","TWN":"做好心理準備後，你將他傳喚到老闆辦公室，得到回應說他馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"후후......","JPN":"ふふ……","ENG":" Hah hah!","TWN":"呵呵……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"하하하하하하!","JPN":"はははははは！","ENG":" Mwa hah hah hah!","TWN":"哈哈哈哈哈哈！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"콜록, 콜록! 크흠, 그래! 역시 이 어둠의 지배자께서 인정한 인물이군!","JPN":"ゲホゲホ！こほん、なるほど！\\nやはりこの闇の支配者に認められし者だ！","ENG":" *Cough, cough* Kahem, yes! You're a great judge of character, just as I, the master of darkness, expected.","TWN":"咳咳，咳咳！咳咳，沒錯！不愧是我這個黑暗支配者所認可的人！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"힘, 지성, 그리고 뛰어난 카리스마까지......","JPN":"力、知性、そして抜群のカリスマ性まで……","ENG":" I have strength, intelligence, and charisma.","TWN":"力量，智慧，還有傑出的領袖魅力……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"이 오오가미 님만큼 매력 넘치는 인물도 찾기 힘들지! 하하핫!","JPN":"この大神様ほど魅力あふれる者もいないだろう！　はははっ！","ENG":" There's no one as charming and capable as Ogami! Hah hah hah!","TWN":"要找到和我大神大人一樣魅力四射的人物，也太難了吧！哈哈哈！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"하지만 최근 들어...... 아주 강력한 호적수가 등장했어.","JPN":"だが、最近になって……とても強力な好敵手が現れた。","ENG":" But I have to admit, a very powerful rival has appeared recently. ","TWN":"不過最近……一個非常強大的好對手登場了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"멋들어지게 어두운 사장실에 머물면서, 다른 녀석들 모르게 활동하고 다니는 녀석이.","JPN":"暗い社長室で優雅に過ごし、他の奴らに気づかれないようにひそかに活躍中の奴だ。","ENG":" This rival of mine moves while no one's watching, devising plans in a cool, dark office. ","TWN":" 一個待在極暗的老闆辦公室裡，暗中進行活動的傢伙。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"훗, 그래. 바로 사장 당신이야.","JPN":"ふっ、そうだ。社長、貴様のことだ。","ENG":" Yes, I'm talking about you.","TWN":"哼，沒錯，說的就是老闆你啊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그동안 지켜보면서 느낀 건데, 경험에서 우러나오는 노련미는 하루 아침에 따라잡을 게 아니더군.","JPN":"今まで貴様を見てきた感想だが、経験から滲み出る風格は一朝一夕で身に付くものじゃないだろう。","ENG":" There's something I learned from you. Expertise isn't something that can be attained overnight. It requires a fair amount of experience.","TWN":" 經過這段時間的觀察，我發現從經驗磨練出來的老練度，不是一天就能追上的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"하지만 괜찮아. 이 몸은 부러움이나 질투 같은 감정으로 대업을 그르칠 사나이가 아니거든.","JPN":"しかし、大丈夫だ。オレ様は羨望とか嫉妬とかの感情で偉業を台無しにする男じゃない。","ENG":" But it doesn't matter. I'm not the kind of man who lets jealousy distract him from his great cause.","TWN":"但是不要緊，本人的大業是不會被羡慕和嫉妒這種情感動搖的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"오히려 완벽한 흑막으로 군림하려면, 널 보고 배워야 한다는 진취적인 결론에 도달해 버렸지!","JPN":"むしろ完璧な黒幕として君臨するためには、貴様を見習う必要があるという前向きな結論を出してしまったんだ！","ENG":" Rather, I came to a very progressive decision that I'd need to learn from you to become the greatest mastermind of them all.","TWN":"不如說要作為一個完美的黑幕君臨天下，就必須向你學習才行，我得出了這個進取的結論！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"후하하하! 방심하지 않는 흑막이라니, 너무 완벽한 거 아니냐고!","JPN":"ふははは！　油断しない黒幕だなんて、完璧すぎないか！","ENG":" Mwa hah hah hah! The ever-wary villain who never comes out of the shadows. How perfect is that?","TWN":"哇哈哈哈！不會大意的黑幕，未免也太完美了吧！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"자, 그렇게 되었으니 어서 계약을 맺어 보기로 할까?","JPN":"というわけだから、さぁ、今すぐ契約を結ぶとしよう。","ENG":" Now, enough talking. Let's see about the contract, shall we?","TWN":"來吧，那我們就簽約吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"뭐? 다시 생각 좀 해 봐야겠다고?","JPN":"何？　考え直すだと？","ENG":" Huh? You're having second thoughts?","TWN":"什麼？你說你要重新考慮一下？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};